defmodule Bank do
  use GenServer

  def start_link(initial_balance) do
    GenServer.start_link(__MODULE__, initial_balance, [])
  end

  def init(balance) do
    {:ok, balance}
  end

  def get_balance(pid) do
    GenServer.call(pid, :get_balance)
  end

  def deposit(pid, amount) do
    GenServer.cast(pid, {:deposit, amount})
  end

  def withdraw(pid, amount) do
    GenServer.cast(pid, {:withdraw, amount})
  end

  def handle_call(:get_balance, _from, balance) do
    {:reply, balance, balance}
  end

  def handle_cast({:deposit, amount}, balance) do
    new_balance = balance + amount
    :ets.insert(:bank_balances, {self(), new_balance})
    {:noreply, new_balance}
  end

  def handle_cast({:withdraw, amount}, balance) do
    case validate_transaction(balance, -amount) do
      true ->
        new_balance = balance + amount
        :ets.insert(:bank_balances, {self(), new_balance})
        {:noreply, new_balance}
      false ->
        IO.puts("Insufficient funds")
        {:noreply, balance}
    end
  end

  defp validate_transaction(balance, amount) do
    if balance >= amount do
      true
    else
      false
    end
  end
end

defmodule BankSupervisor do
  use Supervisor

  def start_link(initial_balance) do
    Supervisor.start_link(__MODULE__, initial_balance)
  end

  def init(initial_balance) do
    children = [
      worker(Bank, [initial_balance], restart: :permanent)
